mapper.select:
SELECT uniqId, userTy, userId , userNm, emailAdres, areaNo, middleTelno, endTelno, moblphonNo, groupId, sttus, sbscrbDe FROM( SELECT ESNTL_ID uniqId, 'USR03' userTy, EMPLYR_ID userId, USER_NM userNm, EMAIL_ADRES emailAdres, AREA_NO areaNo, HOUSE_MIDDLE_TELNO middleTelno, HOUSE_END_TELNO endTelno, MBTLNUM moblphonNo, GROUP_ID groupId, EMPLYR_STTUS_CODE sttus, SBSCRB_DE sbscrbDe FROM member_mst ) A WHERE 1=1
AND sttus LIKE #{sbscrbSttus}
AND userId LIKE #{searchKeyword}
AND userNm LIKE '%' #{searchKeyword} '%'
ORDER BY sbscrbDe DESC LIMIT #{recordCountPerPage} OFFSET #{firstIndex}

SELECT COUNT(1) totcnt FROM( SELECT ESNTL_ID uniqId, 'USR03' userTy, EMPLYR_ID userId, USER_NM userNm, EMAIL_ADRES emailAdres, AREA_NO areaNo, HOUSE_MIDDLE_TELNO middleTelno, HOUSE_END_TELNO endTelno, MBTLNUM moblphonNo, GROUP_ID groupId, EMPLYR_STTUS_CODE sttus, SBSCRB_DE sbscrbDe FROM member_mst ) A WHERE 1=1
AND sttus LIKE #{sbscrbSttus}
AND userId LIKE #{searchKeyword}
AND userNm LIKE '%' #{searchKeyword} '%'

mapper.insert:
INSERT INTO member_mst(   
	ESNTL_ID, EMPLYR_ID, USER_NM, PASSWORD, EMPL_NO, SEXDSTN_CODE,
	BRTHDY, HOUSE_ADRES, DETAIL_ADRES, ZIP,
	MBTLNUM, EMAIL_ADRES, OFCPS_NM, GROUP_ID, ORGNZT_ID, EMPLYR_STTUS_CODE, SBSCRB_DE, CRTFC_DN_VALUE
) VALUES (
	#{uniqId}, #{emplyrId}, #{emplyrNm}, #{password}, #{emplNo}, #{sexdstnCode},
	#{brth}, #{homeadres}, #{detailAdres}, #{zip},
	#{moblphonNo}, #{emailAdres}, #{ofcpsNm}, #{groupId}, #{orgnztId}, #{emplyrSttusCode}, sysdate(), #{subDn}
)

